/**
 * Shared resolution types with action category groupings.
 * Used by MeetingResolutions.tsx and WrittenConsentWizard.tsx.
 */

export interface ResolutionType {
  label: string;
  statute?: string;
  template?: string;
  category?: string;
}

export const ACTION_CATEGORIES = [
  "Banking",
  "Compensation",
  "Financial/Capital Transactions",
  "Governance",
  "Operations",
  "Ownership",
  "Tax Elections",
  "Benefits",
  "Other",
] as const;

export type ActionCategory = (typeof ACTION_CATEGORIES)[number];

// Maps resolution labels to categories
const CATEGORY_MAP: Record<string, ActionCategory> = {
  "Authorize a Line of Credit": "Banking",
  "Approve Officer Bonuses": "Compensation",
  "Approve Officer Bonuses (Reasonable Compensation)": "Compensation",
  "Approve Annual Officer Compensation": "Compensation",
  "Approve Guaranteed Payments": "Compensation",
  "Approve Reasonable Compensation": "Compensation",
  "Approve Issuance of Shares": "Ownership",
  "Approve Transfer/Sale of Shares": "Ownership",
  "Approve Transfer of Membership Interest": "Ownership",
  "Admit New Member": "Ownership",
  "Approve Distributions/Dividends": "Compensation",
  "Approve Distributions": "Compensation",
  "Approve Member Distributions": "Compensation",
  "Elect Officers": "Governance",
  "Elect Directors": "Governance",
  "Elect Directors/Board Members": "Governance",
  "Re-elect Board of Directors": "Governance",
  "Elect/Appoint Managers": "Governance",
  "Re-elect Managers": "Governance",
  "Adopt Regular Meeting Resolution": "Governance",
  "Name Directors to Committees": "Governance",
  "Approve Employment Agreement": "Operations",
  "Approve Employment/Service Agreement": "Operations",
  "Approve Lease Agreement": "Operations",
  "Approve Purchase/Sale of Assets": "Operations",
  "Ratify Prior Actions": "Operations",
  "Approve Tax Election (S-Corp)": "Tax Elections",
  "Approve Tax Classification Election": "Tax Elections",
  "Revoke S-Election": "Tax Elections",
  "Approve Employee Benefit Plan": "Benefits",
  "Approve Amendments to Articles of Incorporation": "Governance",
  "Approve Amendments to Bylaws": "Governance",
  "Approve Amendments to Operating Agreement": "Governance",
  "Approve Amendments to Partnership Agreement": "Governance",
  "Approve Merger or Consolidation": "Governance",
  "Approve Dissolution": "Governance",
  "Approve Authorized Binders": "Governance",
  "Approve Budget": "Operations",
  "Approve Grant Application": "Operations",
  "Approve Fundraising Activity": "Operations",
  "Approve Conflict of Interest Policy": "Governance",
  "Approve Charitable Purpose Activity": "Operations",
  "Approve Partner Distributions": "Compensation",
  "Admit New Partner": "Ownership",
  "Approve Transfer of Partnership Interest": "Ownership",
  "Approve Loan from Related Party": "Financial/Capital Transactions",
  "Approve Loan to Related Party": "Financial/Capital Transactions",
  "Approve Related Party Loan Agreement": "Financial/Capital Transactions",
  "Approve Distributions/Dividends": "Financial/Capital Transactions",
  "Approve Distributions": "Financial/Capital Transactions",
  "Approve Member Distributions": "Financial/Capital Transactions",
  "Approve Partner Distributions": "Financial/Capital Transactions",
  "Authorize a Line of Credit": "Financial/Capital Transactions",
  "Approve AI Governance Policy": "Governance",
  "Universal Resolution": "Governance",
  "Other": "Other",
};

export function getResolutionCategory(label: string): ActionCategory {
  return CATEGORY_MAP[label] || "Other";
}

export function filterByCategory(
  resolutions: ResolutionType[],
  category: ActionCategory
): ResolutionType[] {
  return resolutions.filter(
    (r) => getResolutionCategory(r.label) === category
  );
}

